func formatFloat(n float32) string {
	s := fmt.Sprintf("%.2f", n)

	dot := strings.IndexByte(s, '.')
	intPart := s[:dot]
	fracPart := s[dot:]

	var out []byte
	l := len(intPart)

	for i := range l {
		if i > 0 && (l-i)%3 == 0 {
			out = append(out, ',')
		}
		out = append(out, intPart[i])
	}

	return string(out) + fracPart
}

